patch:
--- a/arithmetic_logic_unit.v
+++ b/arithmetic_logic_unit.v
@@ -7,7 +7,7 @@
   output reg [15:0] alu_result
 );

-  always @(operand_a or opcode)
+  always @(operand_a or operand_b or opcode)
   begin
     case(opcode)
       3'b000: alu_result = operand_a + operand_b;

before_code:
module arithmetic_logic_unit (
  input [15:0] operand_a, operand_b,
  input [2:0] opcode,
  output reg [15:0] alu_result
);

  always @(operand_a or opcode)
  begin
    case(opcode)
      3'b000: alu_result = operand_a + operand_b;
      3'b001: alu_result = operand_a - operand_b;
      3'b010: alu_result = operand_a & operand_b;
      3'b011: alu_result = operand_a | operand_b;
      3'b100: alu_result = operand_a ^ operand_b;
      default: alu_result = 16'h0000;
    endcase
  end
endmodule

after_code:
module arithmetic_logic_unit (
  input [15:0] operand_a, operand_b,
  input [2:0] opcode,
  output reg [15:0] alu_result
);

  always @(operand_a or operand_b or opcode)
  begin
    case(opcode)
      3'b000: alu_result = operand_a + operand_b;
      3'b001: alu_result = operand_a - operand_b;
      3'b010: alu_result = operand_a & operand_b;
      3'b011: alu_result = operand_a | operand_b;
      3'b100: alu_result = operand_a ^ operand_b;
      default: alu_result = 16'h0000;
    endcase
  end
endmodule
